import re
import math
import datetime
import calendar

def clean(x):
    return x.strip()

def words(x):
    return x.split()

def alpha(x):
    return re.sub(r'[^a-zA-Z]', '', x)

def alnum(x):
    return re.sub(r'[^a-zA-Z0-9]', '', x)

def digits(x):
    return re.sub(r'[^0-9]', '', x)

def first_word(x):
    return words(x)[0]

def last_word(x):
    return words(x)[-1]

def word(x, i):
    return words(x)[i]

def field(x, sep, i):
    return sep.join(words(x))[i]

def before(x, sep):
    return sep.join(words(x))[:sep.join(words(x)).index(sep)]

def after(x, sep):
    return sep.join(words(x))[sep.join(words(x)).index(sep)+1:]

def between(x, left, right):
    return sep.join(words(x))[sep.join(words(x)).index(left)+1:sep.join(words(x)).index(right)]

def regex_group(x, pattern, group=1):
    match = re.search(pattern, x)
    if match:
        return match.group(group)
    return ''

def number(x):
    return float(x)

def number_int(x):
    return int(x)

def number_1dp(x):
    return round(float(x), 1)

def number_2dp(x):
    return round(float(x), 2)

def round_to(x, base):
    return round(x / base) * base

def year(x):
    return datetime.datetime.strptime(x, "%Y").year

def month_num(x):
    return datetime.datetime.strptime(x, "%B").month

def month_2(x):
    return datetime.datetime.strptime(x, "%B").strftime("%m")

def month_name(x):
    return datetime.datetime.strptime(x, "%B").strftime("%B")

def month_abbr(x):
    return datetime.datetime.strptime(x, "%B").strftime("%b")

